--- Original
+++ New
@@ -23,11 +23,11 @@
 	// the solution below, works only for utf-8, so in case of a different
 	// charset, just use built-in substr
 	$charset = get_option( 'blog_charset' );
-	if ( !in_array( $charset, array('utf8', 'utf-8', 'UTF8', 'UTF-8') ) ) {
-		return is_null( $length )? substr( $str, $start ) : substr( $str, $start, $length);
+	if ( !in_array( $charset, ['utf8', 'utf-8', 'UTF8', 'UTF-8'] ) ) {
+		return is_null( $length )? substr( (string) $str, $start ) : substr( (string) $str, $start, $length);
 	}
 	// use the regex unicode support to separate the UTF-8 characters into an array
-	preg_match_all( '/./us', $str, $match );
+	preg_match_all( '/./us', (string) $str, $match );
 	$chars = is_null( $length )? array_slice( $match[0], $start ) : array_slice( $match[0], $start, $length );
 	return implode( '', $chars );
 }
@@ -39,7 +39,7 @@
 endif;

 function _hash_hmac($algo, $data, $key, $raw_output = false) {
-	$packs = array('md5' => 'H32', 'sha1' => 'H40');
+	$packs = ['md5' => 'H32', 'sha1' => 'H40'];

 	if ( !isset($packs[$algo]) )
 		return false;
@@ -46,10 +46,10 @@

 	$pack = $packs[$algo];

-	if (strlen($key) > 64)
+	if (strlen((string) $key) > 64)
 		$key = pack($pack, $algo($key));

-	$key = str_pad($key, 64, chr(0));
+	$key = str_pad((string) $key, 64, chr(0));

 	$ipad = (substr($key, 0, 64) ^ str_repeat(chr(0x36), 64));
 	$opad = (substr($key, 0, 64) ^ str_repeat(chr(0x5C), 64));
